# fix_crm_tabs_dark.ps1 - Dark mode para tabs CRM
Write-Host "Aplicando dark mode a tabs CRM..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\crm\components\Activities\ActivitiesPanel.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/modules/crm/components/Activities/ActivitiesPanel.tsx" -ForegroundColor Yellow

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\crm\components\Segmentation\SegmentationPanel.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/modules/crm/components/Segmentation/SegmentationPanel.tsx" -ForegroundColor Yellow

Write-Host "Listo!" -ForegroundColor Green
